module tb;

  // Testbench signals for DUT ports
  reg [2:0] in_tb;
  wire [1:0] out_tb;

  // Verification variables
  integer errors;
  integer i; // Loop variable for test stimuli

  // Instantiate the DUT
  TopModule top_module1 (
    .in  (in_tb),
    .out (out_tb)
  );

  // Task for checking results against expected values
  // Reports a failure if the actual output does not match the expected output.
  task check(input [1:0] expected_out, string test_name);
    #10; // Allow time for combinational logic to propagate
    if (out_tb !== expected_out) begin
      $display("FAIL: %s - Input: %b, Expected: %b, Got: %b", test_name, in_tb, expected_out, out_tb);
      errors = errors + 1;
    end
  endtask

  // Stimulus generation and output checking block
  initial begin
    errors = 0; // Initialize error counter

    $display("--------------------------------------------------");
    $display("Starting Population Count Testbench");
    $display("--------------------------------------------------");

    // Comprehensive test stimuli covering all 2^3 = 8 possible input combinations
    // This covers: all zeros, all ones, one-hot patterns, and other combinations.
    for (i = 0; i < 8; i = i + 1) begin
      in_tb = i; // Assign current loop value to input
      $display("Applying input: in_tb = %b (decimal %0d)", in_tb, i);

      // Determine expected output based on population count logic
      case (in_tb)
        3'b000: check(2'b00, "PopCount 0 ones (000)"); // Expected 0
        3'b001: check(2'b01, "PopCount 1 one (001)");  // Expected 1
        3'b010: check(2'b01, "PopCount 1 one (010)");  // Expected 1
        3'b011: check(2'b10, "PopCount 2 ones (011)"); // Expected 2
        3'b100: check(2'b01, "PopCount 1 one (100)");  // Expected 1
        3'b101: check(2'b10, "PopCount 2 ones (101)"); // Expected 2
        3'b110: check(2'b10, "PopCount 2 ones (110)"); // Expected 2
        3'b111: check(2'b11, "PopCount 3 ones (111)"); // Expected 3
        default: begin // Should not be reached for i < 8
          $display("ERROR: Unexpected input value %b during iteration %0d", in_tb, i);
          errors = errors + 1;
        end
      endcase
    end

    $display("--------------------------------------------------");
    if (errors == 0) begin
      $display("PASS: All population count tests completed successfully.");
    end else begin
      $display("FAIL: %0d errors found during population count testing.", errors);
    end
    $display("--------------------------------------------------");

    $finish; // End simulation after all tests are complete
  end

  // Timeout to prevent infinite simulation
  initial begin
    #1000000 $display("TIMEOUT: Simulation exceeded maximum allowed time.");
    $finish;
  end

endmodule

