module tb;

  // Declare testbench signals for DUT inputs and outputs
  // 'reg' for signals driven by initial/always blocks
  // 'wire' for signals driven by the DUT
  reg in1_tb;
  reg in2_tb;
  wire out_tb;

  // Declare variables for tracking test status
  integer errors;
  integer total_tests;

  // Instantiate the Design Under Test (DUT)
  TopModule top_module1 (
    .in1(in1_tb),
    .in2(in2_tb),
    .out(out_tb)
  );

  // Helper task to check the output and report status
  // This task aligns with the checking pattern suggested in combinational-verify skill
  // Corrected for Verilog-2001:
  // - Removed 'reg' keyword from 'input expected_out' as it's implicit in Verilog-2001 tasks.
  // - Changed 'input string test_name' to 'input [8*128-1:0] test_name'
  //   as 'string' type is SystemVerilog and not Verilog-2001 compatible.
  //   A wide 'reg' is used to pass string literals.
  task check_output;
    input expected_out; // Verilog-2001 task inputs are implicitly 'reg'
    input [8*128-1:0] test_name; // Use wide reg for string literals in Verilog-2001
    begin
      total_tests = total_tests + 1;
      #10; // Allow for propagation delay in the DUT

      if (out_tb !== expected_out) begin
        $display("FAIL: %s - Input in1=%b, in2=%b. Expected out=%b, got out=%b",
                 test_name, in1_tb, in2_tb, expected_out, out_tb);
        errors = errors + 1;
      end
      // No $display for passing individual tests, only for failures as per guidelines
    end
  endtask

  // Initial block for stimulus generation and overall test control
  initial begin
    // Initialize error counter and total tests
    errors = 0;
    total_tests = 0;

    $display("---------------------------------------");
    $display("Starting NOR Gate Testbench Simulation");
    $display("---------------------------------------");

    // Test Case 1: in1=0, in2=0 -> Expected out=1
    in1_tb = 1'b0;
    in2_tb = 1'b0;
    check_output(1'b1, "Test Case 1 (in1=0, in2=0)");

    // Test Case 2: in1=0, in2=1 -> Expected out=0
    in1_tb = 1'b0;
    in2_tb = 1'b1;
    check_output(1'b0, "Test Case 2 (in1=0, in2=1)");

    // Test Case 3: in1=1, in2=0 -> Expected out=0
    in1_tb = 1'b1;
    in2_tb = 1'b0;
    check_output(1'b0, "Test Case 3 (in1=1, in2=0)");

    // Test Case 4: in1=1, in2=1 -> Expected out=0
