    .clk(clk),
    .reset(reset),
    .d(d),
    .q(q)
  );

  // Clock generation
  initial begin
    clk = 0; // Initialize clock
  end

  always #(CLK_PERIOD/2) clk = ~clk; // Toggle clock every half period

  // Test stimulus and checking
  initial begin
    errors = 0; // Initialize error counter

    // Timeout to prevent infinite simulation
    fork
      #1000000 $display("FAIL: Simulation timed out."); $finish;
    join_none

    // 1. Initialize and apply reset
    $display("--- Starting DFF8R Test ---");
    $display("Applying reset for 2 clock cycles...");
    reset = 1;
    d = 8'h00; // Initialize d to a known value
    expected_q = 8'h00; // Expected output after reset

    # (CLK_PERIOD * 2); // Hold reset for 2 clock cycles

    // Check q after reset
    @(posedge clk); // Wait for a clock edge for reset to take effect
    if (q !== expected_q) begin
      $display("FAIL: Reset check failed. Expected q = %h, Got q = %h", expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Reset check successful. q = %h", q);
    end

    // 2. Release reset and apply data
    reset = 0;
    $display("--- Testing DFF functionality ---");

    // Test case 1: d = 8'h5A
    d = 8'h5A;
    @(posedge clk); // Clock edge for DFF to capture d
    expected_q = 8'h5A;
    if (q !== expected_q) begin
      $display("FAIL: Test case 1 failed (d=%h). Expected q = %h, Got q = %h", d, expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Test case 1 successful (d=%h). q = %h", d, q);
    end

    // Test case 2: d = 8'hA5
    d = 8'hA5;
    @(posedge clk);
    expected_q = 8'hA5;
    if (q !== expected_q) begin
      $display("FAIL: Test case 2 failed (d=%h). Expected q = %h, Got q = %h", d, expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Test case 2 successful (d=%h). q = %h", d, q);
    end

    // Test case 3: d = 8'hFF (all ones)
    d = 8'hFF;
    @(posedge clk);
    expected_q = 8'hFF;
    if (q !== expected_q) begin
      $display("FAIL: Test case 3 failed (d=%h). Expected q = %h, Got q = %h", d, expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Test case 3 successful (d=%h). q = %h", d, q);
    end

    // Test case 4: d = 8'h00 (all zeros)
    d = 8'h00;
    @(posedge clk);
    expected_q = 8'h00;
    if (q !== expected_q) begin
      $display("FAIL: Test case 4 failed (d=%h). Expected q = %h, Got q = %h", d, expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Test case 4 successful (d=%h). q = %h", d, q);
    end

    // Test case 5: Sequence of random-like values
    for (i = 0; i < 10; i = i + 1) begin
      d = i * 16 + (i % 8) + (i << 2); // Generate some varying data
      @(posedge clk);
      expected_q = d; // q should capture the d from the previous cycle
      if (q !== expected_q) begin
        $display("FAIL: Test case sequence failed (i=%0d, d=%h). Expected q = %h, Got q = %h", i, d, expected_q, q);
        errors = errors + 1;
      end else begin
        $display("PASS: Test case sequence successful (i=%0d, d=%h). q = %h", i, d, q);
      end
    end

    // 3. Re-apply reset during operation
    $display("--- Testing synchronous reset during operation ---");
    d = 8'hAA;
    @(posedge clk); // Capture AA into q
    expected_q = 8'hAA;
    if (q !== expected_q) begin
      $display("FAIL: Pre-reset capture failed. Expected q = %h, Got q = %h", expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Pre-reset capture successful. q = %h", q);
    end

    // Now apply reset and check if q goes to 0
    reset = 1;
    d = 8'hFF; // Change d to something else to ensure reset overrides it
    @(posedge clk); // Reset should take effect on this clock edge
    expected_q = 8'h00; // Expected output after reset
    if (q !== expected_q) begin
      $display("FAIL: Synchronous reset during operation failed. Expected q = %h, Got q = %h", expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Synchronous reset during operation successful. q = %h", q);
    end

    // Release reset
    reset = 0;
    @(posedge clk); // Wait for one cycle to release reset, q should remain 0
    expected_q = 8'h00; // q should still be 0 as d was FF, but reset cleared it.
                        // Now it will capture d on next clock.
    if (q !== expected_q) begin
      $display("FAIL: Reset release check failed. Expected q = %h, Got q = %h", expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Reset release check successful. q = %h", q);
    end

    // Final check after releasing reset
    d = 8'h3C;
    @(posedge clk);
    expected_q = 8'h3C;
    if (q !== expected_q) begin
      $display("FAIL: Post-reset capture failed. Expected q = %h, Got q = %h", expected_q, q);
      errors = errors + 1;
    end else begin
      $display("PASS: Post-reset capture successful. q = %h", q);
    end

    // Final summary
    $display("--- Test Summary ---");
    if (errors == 0) begin
      $display("PASS: All tests completed successfully.");
    end else begin
      $display("FAIL: %0d errors found during testing.", errors);
    end

    #10; // Small delay before finishing
    $finish;
  end

