    $finish;
  end

  // Test sequence
  initial begin
    errors = 0;

    // Initialize inputs to a known state
    w = 0;
    R = 0;
    E = 0;
    L = 0;

    $display("--------------------------------------------------");
    $display("Starting TopModule Shift Register Testbench");
    $display("--------------------------------------------------");

    // Wait for a few clock cycles for initial stability
    repeat (2) @(posedge clk);

    // Test Case 1: Initial Load (L=1, R=0) - Clear Q
    $display("TC1: Initial Load R=0 (Clear Q)");
    L = 1;
    R = 0;
    E = 0; // E should not matter when L is high
    w = 1; // w should not matter when L is high
    @(posedge clk);
    #1; // Allow time for output to settle
    if (Q !== 0) begin
      $display("FAIL: TC1 - Expected Q=0 after L=1, R=0. Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC1 - Q cleared to 0.");
    end

    // Test Case 2: Load R=1
    $display("TC2: Load R=1");
    L = 1;
    R = 1;
    E = 0;
    w = 0;
    @(posedge clk);
    #1;
    if (Q !== 1) begin
      $display("FAIL: TC2 - Expected Q=1 after L=1, R=1. Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC2 - Q loaded with 1.");
    end

    // Test Case 3: Hold current value (L=0, E=0)
    $display("TC3: Hold current value (L=0, E=0)");
    L = 0;
    R = 0; // R should not matter
    E = 0;
    w = 0; // w should not matter
    @(posedge clk);
    #1;
    if (Q !== 1) begin
      $display("FAIL: TC3 - Expected Q=1 (hold) after L=0, E=0. Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC3 - Q held value 1.");
    end

    // Test Case 4: Shift w=0 (Q was 1)
    $display("TC4: Shift w=0 (Q was 1)");
    L = 0;
    R = 1; // R should not matter
    E = 1;
    w = 0;
    @(posedge clk);
    #1;
    if (Q !== 0) begin
      $display("FAIL: TC4 - Expected Q=0 after shift w=0. Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC4 - Q shifted to 0.");
    end

    // Test Case 5: Shift w=1 (Q was 0)
    $display("TC5: Shift w=1 (Q was 0)");
    L = 0;
    R = 0; // R should not matter
    E = 1;
    w = 1;
    @(posedge clk);
    #1;
    if (Q !== 1) begin
      $display("FAIL: TC5 - Expected Q=1 after shift w=1. Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC5 - Q shifted to 1.");
    end

    // Test Case 6: Priority check (L=1, E=1, R=0, w=1) - L should override E
    $display("TC6: Priority check L=1, E=1, R=0, w=1 (L should override E)");
    L = 1;
    R = 0;
    E = 1; // E is active, but L should take priority
    w = 1; // w is active, but L should take priority
    @(posedge clk);
    #1;
    if (Q !== 0) begin
      $display("FAIL: TC6 - Expected Q=0 (from R) when L=1, E=1. Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC6 - Q loaded 0, L has priority.");
    end

    // Test Case 7: Complex sequence: Hold -> Load -> Shift -> Hold
    $display("TC7: Complex sequence: Hold -> Load -> Shift -> Hold");

    // Hold (Q=0)
    L = 0; E = 0; R = 1; w = 1; // Inputs set, but Q should hold
    @(posedge clk);
    #1;
    if (Q !== 0) begin
      $display("FAIL: TC7.1 - Expected Q=0 (hold). Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC7.1 - Q held 0.");
    end

    // Load R=1
    L = 1; E = 0; R = 1; w = 0; // Load 1
    @(posedge clk);
    #1;
    if (Q !== 1) begin
      $display("FAIL: TC7.2 - Expected Q=1 (load). Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC7.2 - Q loaded 1.");
    end

    // Shift w=0
    L = 0; E = 1; R = 0; w = 0; // Shift 0
    @(posedge clk);
    #1;
    if (Q !== 0) begin
      $display("FAIL: TC7.3 - Expected Q=0 (shift). Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC7.3 - Q shifted 0.");
    end

    // Hold (Q=0)
    L = 0; E = 0; R = 1; w = 1; // Inputs set, but Q should hold
    @(posedge clk);
    #1;
    if (Q !== 0) begin
      $display("FAIL: TC7.4 - Expected Q=0 (hold). Got Q=%b", Q);
      errors = errors + 1;
    end else begin
      $display("PASS: TC7.4 - Q held 0.");
    end

    $display("--------------------------------------------------");
    if (errors == 0) begin
      $display("All tests passed!");
      $display("PASS");
    end else begin
      $display("Total errors: %0d", errors);
      $display("FAIL");
    end
    $finish;
  end

