    input [100:0] test_name; // String for test description
    input         expected_q; // Expected value of q
    begin
      test_count = test_count + 1;
      // Wait a small delta time for combinatorial logic to settle after sequential update
      #1;
      if (q !== expected_q) begin
        $display("FAIL: %s - At time %0t, Expected q=%b, Got q=%b", test_name, $time, expected_q, q);
        error_count = error_count + 1;
      end else begin
        $display("INFO: %s - At time %0t, q=%b (Expected)", test_name, $time, q);
      end
    end
  endtask

