    // We'll let the first edge define q
    @(negedge clk); // Ensure clk is stable at 0 before first test
    $display("INFO: Initializing inputs. Waiting for first edge...");

    // --- Test Case 1: Positive edge trigger ---
    d = 1;
    $display("INFO: d set to 1. Waiting for posedge clk...");
    @(posedge clk); // d=1, clk=0->1, q should become 1
    check_output("Pos edge trigger d=1", 1);

    // --- Test Case 2: Negative edge trigger ---
    d = 0;
    $display("INFO: d set to 0. Waiting for negedge clk...");
    @(negedge clk); // d=0, clk=1->0, q should become 0
    check_output("Neg edge trigger d=0", 0);

    // --- Test Case 3: Alternating edges with changing data ---
    d = 1;
    $display("INFO: d set to 1. Waiting for posedge clk...");
    @(posedge clk); // d=1, q should become 1
    check_output("Alternating: d=1 on posedge", 1);

