    $display("INFO: d set to 1. Waiting for posedge clk...");
    @(posedge clk); // d=1, q should become 1
    check_output("Alternating: d=1 on posedge", 1);

    d = 0;
    $display("INFO: d set to 0. Waiting for negedge clk...");
    @(negedge clk); // d=0, q should become 0
    check_output("Alternating: d=0 on negedge", 0);

