    d = 1;
    $display("INFO: d set to 1. Data held for multiple edges.");
    @(posedge clk); // d=1, q should become 1
    check_output("Data stable: d=1 on posedge", 1);

    @(negedge clk); // d=1, q should remain 1
    check_output("Data stable: d=1 on negedge", 1);

    @(posedge clk); // d=1, q should remain 1
    check_output("Data stable: d=1 on posedge", 1);

    d = 0;
    $display("INFO: d set to 0. Data held for multiple edges.");
    @(negedge clk); // d=0, q should become 0
    check_output("Data stable: d=0 on negedge", 0);

    @(posedge clk); // d=0, q should remain 0
    check_output("Data stable: d=0 on posedge", 0);

    // --- Test Case 5: Rapid data changes (d changes right after an edge) ---
    d = 1;
    @(posedge clk);
    check_output("Rapid change: d=1 on posedge", 1);
    d = 0; // Change d immediately after posedge
    $display("INFO: d changed to 0 immediately after posedge.");

    @(negedge clk); // d=0, q should become 0
    check_output("Rapid change: d=0 on negedge", 0);
    d = 1; // Change d immediately after negedge
    $display("INFO: d changed to 1 immediately after negedge.");

    @(posedge clk); // d=1, q should become 1
    check_output("Rapid change: d=1 on posedge", 1);
    d = 0;
    $display("INFO: d changed to 0 immediately after posedge.");

    @(negedge clk); // d=0, q should become 0
    check_output("Rapid change: d=0 on negedge", 0);
    d = 1;
    $display("INFO: d changed to 1 immediately after negedge.");

    // Final checks
    $display("--------------------------------------------------");
    if (error_count == 0) begin
      $display("PASS: All %0d tests completed successfully.", test_count);
    end else begin
      $display("FAIL: %0d out of %0d tests failed.", error_count, test_count);
    end
    $display("--------------------------------------------------");

    $finish; // End simulation
  end

