    .j(j),
    .k(k),
    .out(out)
  );

  // Test sequence
  initial begin
    failure_detected = 0;
    test_count = 0;

    // Initialize inputs
    areset = 1; // Active reset
    j = 0;
    k = 0;

    $display("--------------------------------------------------");
    $display("Starting Moore FSM Testbench");
    $display("--------------------------------------------------");

    // 1. Apply Reset - Expect OFF (out=0)
    $display("TIME: %0t - Applying reset...", $time);
    #10; // Allow reset to settle, wait for a full clock cycle
    expected_out = 0;
    if (out !== expected_out) begin
      $display("FAIL: Initial reset, out=%b, expected=%b", out, expected_out);
      failure_detected = 1;
    end else begin
      $display("PASS: Initial reset, out=%b", out);
    end
    test_count = test_count + 1;

    areset = 0; // Release reset
    $display("TIME: %0t - Releasing reset...", $time);

    // Wait for a clock edge to ensure state transition logic is active after reset release
    #10; // Wait for one clock cycle to ensure the state machine is ready

    // 2. OFF (out=0) --j=1--> ON (out=1)
    $display("TIME: %0t - Current state: OFF (out=%b). Transitioning to ON (j=1)...", $time, out);
    j = 1;
    k = 0; // k is don't care for OFF state transitions
    @(posedge clk);
    #1; // Allow output to propagate
    expected_out = 1;
    if (out !== expected_out) begin
      $display("FAIL: OFF -> ON (j=1). out=%b, expected=%b", out, expected_out);
      failure_detected = 1;
    end else begin
      $display("PASS: OFF -> ON (j=1). out=%b", out);
    end
    test_count = test_count + 1;

    // 3. ON (out=1) --k=0--> ON (out=1)
    $display("TIME: %0t - Current state: ON (out=%b). Transitioning to ON (k=0)...", $time, out);
    j = 0; // j is don't care for ON state transitions
    k = 0;
    @(posedge clk);
    #1; // Allow output to propagate
    expected_out = 1;
    if (out !== expected_out) begin
      $display("FAIL: ON -> ON (k=0). out=%b, expected=%b", out, expected_out);
      failure_detected = 1;
    end else begin
      $display("PASS: ON -> ON (k=0). out=%b", out);
    end
    test_count = test_count + 1;

    // 4. ON (out=1) --k=1--> OFF (out=0)
    $display("TIME: %0t - Current state: ON (out=%b). Transitioning to OFF (k=1)...", $time, out);
    j = 0; // j is don't care for ON state transitions
    k = 1;
    @(posedge clk);
    #1; // Allow output to propagate
    expected_out = 0;
    if (out !== expected_out) begin
      $display("FAIL: ON -> OFF (k=1). out=%b, expected=%b", out, expected_out);
      failure_detected = 1;
    end else begin
      $display("PASS: ON -> OFF (k=1). out=%b", out);
    end
    test_count = test_count + 1;

    // 5. OFF (out=0) --j=0--> OFF (out=0)
    $display("TIME: %0t - Current state: OFF (out=%b). Transitioning to OFF (j=0)...", $time, out);
    j = 0;
    k = 0; // k is don't care for OFF state transitions
    @(posedge clk);
    #1; // Allow output to propagate
    expected_out = 0;
    if (out !== expected_out) begin
      $display("FAIL: OFF -> OFF (j=0). out=%b, expected=%b", out, expected_out);
      failure_detected = 1;
    end else begin
      $display("PASS: OFF -> OFF (j=0). out=%b", out);
    end
    test_count = test_count + 1;

    // 6. Re-apply Reset - Expect OFF (out=0)
    $display("TIME: %0t - Re-applying reset...", $time);
    areset = 1;
    j = 0;
    k = 0;
    #10; // Allow reset to settle
    expected_out = 0;
    if (out !== expected_out) begin
      $display("FAIL: Re-apply reset, out=%b, expected=%b", out, expected_out);
      failure_detected = 1;
    end else begin
      $display("PASS: Re-apply reset, out=%b", out);
    end
    test_count = test_count + 1;

    $display("--------------------------------------------------");
    if (failure_detected) begin
      $display("Test FAILED: %0d checks performed, some failures detected.", test_count);
      $display("FAIL");
    end else begin
      $display("Test PASSED: All %0d checks successful.", test_count);
      $display("PASS");
    end
    $display("--------------------------------------------------");

    $finish;
  end

  // Timeout to prevent infinite simulation
  initial begin
