  integer i;
  reg     expected_f;
  integer errors = 0; // Initialize errors to 0

  // Instantiate the DUT
  TopModule top_module1 (
    .x (x_tb),
    .f (f_tb)
  );

  // Task to check output against expected value
  // This task uses Verilog-2001 compatible types for arguments.
  task check(input reg expected_val, input reg actual_val, input integer test_case_num);
    begin
      if (actual_val !== expected_val) begin
        $display("FAIL: Test case %0d (x = 4'h%x): Expected f = %b, Got f = %b", test_case_num, x_tb, expected_val, actual_val);
        errors = errors + 1;
      end else begin
        $display("PASS: Test case %0d (x = 4'h%x): f = %b (Correct)", test_case_num, x_tb, actual_val);
      end
    end
  endtask


  // Main test sequence
  initial begin
    $display("Starting TopModule verification...");

    // Initialize inputs
    x_tb = 4'h0;
    #1; // Allow combinational logic to settle before first check

    // Iterate through all 16 possible input combinations (0 to 15)
    for (i = 0; i < 16; i = i + 1) begin
      x_tb = i;

      // Determine expected output based on the Karnaugh map (specification)
      // K-map:
      //              x[0]x[1]
      // x[2]x[3]  00  01  11  10
      //   00     | 1 | 0 | 0 | 1 |  (x=0,1,3,2)
      //   01     | 0 | 0 | 0 | 0 |  (x=4,5,7,6)
      //   11     | 1 | 1 | 1 | 0 |  (x=C,D,F,E)
      //   10     | 1 | 1 | 0 | 1 |  (x=8,9,B,A)
      case (x_tb)
        4'h0: expected_f = 1; // x[3:0]=0000 -> 1
        4'h1: expected_f = 0; // x[3:0]=0001 -> 0
        4'h2: expected_f = 1; // x[3:0]=0010 -> 1
        4'h3: expected_f = 0; // x[3:0]=0011 -> 0
        4'h4: expected_f = 0; // x[3:0]=0100 -> 0
        4'h5: expected_f = 0; // x[3:0]=0101 -> 0
        4'h6: expected_f = 0; // x[3:0]=0110 -> 0
        4'h7: expected_f = 0; // x[3:0]=0111 -> 0
        4'h8: expected_f = 1; // x[3:0]=1000 -> 1
        4'h9: expected_f = 1; // x[3:0]=1001 -> 1
        4'ha: expected_f = 1; // x[3:0]=1010 -> 1
        4'hb: expected_f = 0; // x[3:0]=1011 -> 0
        4'hc: expected_f = 1; // x[3:0]=1100 -> 1
        4'hd: expected_f = 1; // x[3:0]=1101 -> 1
        4'he: expected_f = 0; // x[3:0]=1110 -> 0
        4'hf: expected_f = 1; // x[3:0]=1111 -> 1
        default: expected_f = 1'bx; // Should not be reached for 4-bit input
      endcase

      #1; // Wait for combinational logic to propagate and output to settle

      // Call the check task
      check(expected_f, f_tb, i);
    end

    // Report final pass/fail status
    if (errors == 0) begin
      $display("****************************************");
      $display("ALL TESTS PASSED for TopModule!");
      $display("****************************************");
    end else begin
      $display("****************************************");
      $display("FAIL: %0d errors found in TopModule verification.", errors);
      $display("****************************************");
    end

    $finish; // End simulation
  end

  // Timeout block: This runs concurrently with the main test sequence.
  // If the main sequence finishes and calls $finish, this block will be terminated.
  // If the main sequence hangs, this block will eventually trigger the timeout.
  initial begin
    #1000000 $display("FAIL: Simulation timed out."); // Added missing closing quote
    $finish; // End simulation on timeout
  end

endmodule

