module tb;

  // DUT signals
  reg clk;
  reg reset;
  reg x;
  wire z;

  // Testbench internal variables
  // Using direct bit values to avoid parameter name conflicts with DUT
  reg [2:0] expected_state_reg; // To track the expected state of the FSM (like DUT's state register)
  reg [2:0] next_expected_state_comb; // To calculate the next expected state combinatorially
  reg expected_z; // To store the expected output z
  integer error_count; // Counter for verification errors
  integer i; // Loop counter

  // Instantiate the DUT
  TopModule top_module1 (
    .clk(clk),
    .reset(reset),
    .x(x),
    .z(z)
  );

  // Clock generation
  always #5 clk = ~clk;

  // Expected FSM model: Sequential part (state register)
  always @(posedge clk) begin
    if (reset) begin
      expected_state_reg <= 3'b000; // State A
    end else begin
      expected_state_reg <= next_expected_state_comb;
    end
  end

  // Expected FSM model: Combinational part (next state and output logic)
  always @(*) begin
    // Default assignments to avoid latches, though case statement should cover all states
    next_expected_state_comb = 3'b000; // Default to A, or X for unknown
    expected_z = 1'b0;

    case (expected_state_reg)
      3'b000: begin // State A
        next_expected_state_comb = x ? 3'b001 : 3'b000; // B : A
        expected_z = 1'b0;
      end
      3'b001: begin // State B
        next_expected_state_comb = x ? 3'b100 : 3'b001; // E : B
        expected_z = 1'b0;
      end
      3'b010: begin // State C
        next_expected_state_comb = x ? 3'b001 : 3'b010; // B : C
        expected_z = 1'b0;
      end
      3'b011: begin // State D
        next_expected_state_comb = x ? 3'b010 : 3'b001; // C : B
        expected_z = 1'b1;
      end
      3'b100: begin // State E
        next_expected_state_comb = x ? 3'b100 : 3'b011; // E : D
        expected_z = 1'b1;
      end
      default: begin
        next_expected_state_comb = 3'bx; // Unknown state
        expected_z = 1'bx;
      end
    endcase
  end


  initial begin
    // Initialize signals
    clk = 1'b0;
    reset = 1'b1;
    x = 1'b0;
    error_count = 0;
    expected_state_reg = 3'b000; // Initialize expected state to A

    $display("------------------------------------------------------------------");
    $display("Starting FSM Testbench");
    $display("------------------------------------------------------------------");

    // Apply reset for a few clock cycles
    #10; // Wait for clock to become stable
    reset = 1'b1;
    repeat (2) @(posedge clk); // Hold reset for 2 clock cycles
    reset = 1'b0;
    $display("Reset complete. FSM should be in state 000 (A).");

    // Test sequence
    // Using a loop to generate various inputs
    for (i = 0; i < 20; i = i + 1) begin
      // Apply random or specific inputs
      @(posedge clk);
      x = $random % 2; // Randomly set x to 0 or 1

      // After clock edge, check outputs and state
      #1; // Allow combinational logic to settle

      $display("Time: %0t, Input x: %b, Current DUT state: %b, Expected state: %b, DUT z: %b, Expected z: %b",
               $time, x, top_module1.state, expected_state_reg, z, expected_z);

      // Check state
      if (top_module1.state !== expected_state_reg) begin
        $display("FAIL: State mismatch at time %0t. DUT state: %b, Expected: %b",
                 $time, top_module1.state, expected_state_reg);
        error_count = error_count + 1;
      end

      // Check output z
      if (z !== expected_z) begin
        $display("FAIL: Output z mismatch at time %0t. DUT z: %b, Expected: %b",
                 $time, z, expected_z);
        error_count = error_count + 1;
      end
    end

    // Additional specific test cases or edge cases
    $display("\nRunning specific test cases:");
    // Test case: A -> B -> E -> E (x=1 continuously)
    @(posedge clk); x = 1'b1; #1;
    $display("Time: %0t, Input x: %b, Current DUT state: %b, Expected state: %b, DUT z: %b, Expected z: %b", $time, x, top_module1.state, expected_state_reg, z, expected_z);
    if (top_module1.state !== expected_state_reg) begin $display("FAIL: State mismatch. Expected %b, Got %b", expected_state_reg, top_module1.state); error_count = error_count + 1; end
    if (z !== expected_z) begin $display("FAIL: Output z mismatch. Expected %b, Got %b", expected_z, z); error_count = error_count + 1; end

    @(posedge clk); x = 1'b1; #1;
    $display("Time: %0t, Input x: %b, Current DUT state: %b, Expected state: %b, DUT z: %b, Expected z: %b", $time, x, top_module1.state, expected_state_reg, z, expected_z);
    if (top_module1.state !== expected_state_reg) begin $display("FAIL: State mismatch. Expected %b, Got %b", expected_state_reg, top_module1.state); error_count = error_count + 1; end
    if (z !== expected_z) begin $display("FAIL: Output z mismatch. Expected %b, Got %b", expected_z, z); error_count = error_count + 1; end

    @(posedge clk); x = 1'b1; #1;
    $display("Time: %0t, Input x: %b, Current DUT state: %b, Expected state: %b, DUT z: %b, Expected z: %b", $time, x, top_module1.state, expected_state_reg, z, expected_z);
    if (top_module1.state !== expected_state_reg) begin $display("FAIL: State mismatch. Expected %b, Got %b", expected_state_reg, top_module1.state); error_count = error_count + 1; end
    if (z !== expected_z) begin $display("FAIL: Output z mismatch. Expected %b, Got %b", expected_z, z); error_count = error_count + 1; end

    // Test case: E -> D -> B -> E (x=0, then x=1)
    @(posedge clk); x = 1'b0; #1; // E -> D
    $display("Time: %0t, Input x: %b, Current DUT state: %b, Expected state: %b, DUT z: %b, Expected z: %b", $time, x, top_module1.state, expected_state_reg, z, expected_z);
