    if (z !== expected_z) begin $display("FAIL: Output z mismatch. Expected %b, Got %b", expected_z, z); error_count = error_count + 1; end

    @(posedge clk); x = 1'b1; #1; // B -> E
    $display("Time: %0t, Input x: %b, Current DUT state: %b, Expected state: %b, DUT z: %b, Expected z: %b", $time, x, top_module1.state, expected_state_reg, z, expected_z);
    if (top_module1.state !== expected_state_reg) begin $display("FAIL: State mismatch. Expected %b, Got %b", expected_state_reg, top_module1.state); error_count = error_count + 1; end
    if (z !== expected_z) begin $display("FAIL: Output z mismatch. Expected %b, Got %b", expected_z, z); error_count = error_count + 1; end


    // Final status report
    $display("------------------------------------------------------------------");
    if (error_count == 0) begin
      $display("PASS: All tests completed successfully.");
    end else begin
      $display("FAIL: %0d errors found during simulation.", error_count);
    end
    $display("------------------------------------------------------------------");

    $finish;
  end

  // Timeout to prevent infinite simulation
  initial begin
    #1000000 $display("FAIL: Simulation timed out!"). $finish;
  end

endmodule

